(async () => {
  const moreMenu = document.querySelector('[aria-label="More"]');
  if (!moreMenu) return [{ status: 'failed', message: 'Could not find More menu' }];

  moreMenu.click();
  await new Promise(r => setTimeout(r, 1000));

  const items = document.querySelectorAll('[role="menuitem"]');
  let deleteBtn = null;
  for (const item of items) {
    if (item.textContent.includes('Delete') && !item.textContent.includes('List')) {
      deleteBtn = item;
      break;
    }
  }

  if (!deleteBtn) return [{ status: 'failed', message: 'Delete option not found (not your tweet)' }];

  deleteBtn.click();
  await new Promise(r => setTimeout(r, 1000));

  const confirmBtn = document.querySelector('[data-testid="confirmationSheetConfirm"]');
  if (confirmBtn) {
    confirmBtn.click();
    await new Promise(r => setTimeout(r, 2000));
    return [{ status: 'success', message: 'Tweet successfully deleted' }];
  } else {
    return [{ status: 'failed', message: 'Delete confirmation dialog did not appear' }];
  }
})()
